import widgetCardStylesText from '../widget-card.css?inline';
import widgetStylesText from './health-summary-widget.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { navigate } from '../../../router.js';
import { createWidgetStatusMixin } from '../../_shared/widget-status.js';
import { HealthService } from '../../../services/health.service.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { appTodayString } from '../../../services/app-timezone.service.js';
import { safeExec } from '../../../utils/safe-exec.js';
import { formatMacro } from '../../../utils/format-macro.js';
import { MEAL_TYPES } from '@motivation/shared';
import type { MealType } from '@motivation/shared';

const widgetCardStyles = cssStyleSheet(widgetCardStylesText);
const widgetStyles = cssStyleSheet(widgetStylesText);
const log = createComponentLogger('home/health-summary-widget');

const MEAL_ICONS: Record<MealType, string> = {
    Breakfast: '🥣',
    Lunch: '🥪',
    Dinner: '🍴',
    Snacks: '🍌',
};

const template = document.createElement('template');
template.innerHTML = `
    <div class="widget-header">
        <h2 class="widget-title">Health</h2>
    </div>
    <ul class="meals" id="meals">
        ${MEAL_TYPES.map((meal) => `
            <li class="meal" data-meal="${meal}">
                <span class="meal-icon" aria-hidden="true">${MEAL_ICONS[meal]}</span>
                <span class="meal-name">${meal}</span>
                <span class="meal-kcal" data-kcal="${meal}">0 kcal</span>
            </li>
        `).join('')}
    </ul>
    <button type="button" class="log-food" id="log-food">Log food</button>
`;

export class HealthSummaryWidget extends HTMLElement {
    private status!: ReturnType<typeof createWidgetStatusMixin>;

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.status = createWidgetStatusMixin(this);
        this.shadowRoot!.adoptedStyleSheets = [widgetCardStyles, widgetStyles];
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        this.style.setProperty('--widget-color', 'var(--color-health, #e6b800)');
    }

    setLoading() { this.status.setLoading(); }
    setError(err: unknown) { this.status.setError(err); }
    clearStatus() { this.status.clearStatus(); }

    connectedCallback() {
        this.addEventListener('click', () => navigate('/health'));

        const logFoodBtn = this.shadowRoot!.getElementById('log-food')!;
        logFoodBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            navigate('/health/food-entry');
        });

        this.refresh();
    }

    async refresh() {
        await safeExec(this, log, () => this.loadData());
    }

    private async loadData() {
        const today = appTodayString();
        const entries = await HealthService.fetchConsumptionByDate(today);

        const totals: Record<MealType, number> = {
            Breakfast: 0,
            Lunch: 0,
            Dinner: 0,
            Snacks: 0,
        };
        for (const entry of entries) {
            totals[entry.meal_type] += entry.calories ?? 0;
        }

        for (const meal of MEAL_TYPES) {
            const cell = this.shadowRoot!.querySelector(`[data-kcal="${meal}"]`)!;
            cell.textContent = `${formatMacro(totals[meal])} kcal`;
        }
    }
}

if (!customElements.get('health-summary-widget')) {
    customElements.define('health-summary-widget', HealthSummaryWidget);
}
